        }
        user, err := c.generateUserPasswdEntry(0)
@@ -44,7 +44,7 @@ func TestGenerateUserGroupEntry(t *testing.T) {
                        },
                },
                state: &ContainerState{
-                       Mountpoint: "/does/not/exist/tmp/",
